import { cursor } from './stores/cursor';
import { difficulty } from './stores/difficulty';
import { gamePaused } from './stores/game';
import { candidates } from './stores/candidates';
import { currentGame, grid } from './stores/grid';
import { notes } from './stores/notes';
import { timer } from './stores/timer';
import { hints } from './stores/hints';

function resetUiState() {
	cursor.reset();
	timer.reset();
	hints.reset();
	candidates.reset();
	notes.reset();
}

export function startNew(diff) {
	difficulty.set(diff);
	grid.generate(diff);
	resetUiState();
	location.hash = '';
}

export function startCustom(sencode) {
	difficulty.setCustom();
	grid.decodeSencode(sencode);
	resetUiState();
}

export function loadSavedGame(jsonText) {
	const parsed = JSON.parse(jsonText);
	currentGame.loadFromJSON(parsed);
	difficulty.setCustom();
	resetUiState();
}

export function exportSavedGame() {
	return JSON.stringify(currentGame.toJSON(), null, 2);
}

export function getGameDebugText() {
	return currentGame.toString();
}

export function canLoadSavedGame(value) {
	try {
		const parsed = JSON.parse(value);
		return Boolean(parsed && parsed.initialGrid && parsed.sudoku && parsed.sudoku.grid);
	} catch {
		return false;
	}
}

export function undo() {
	currentGame.undo();
}

export function redo() {
	currentGame.redo();
}

export function startExplore() {
	return currentGame.startExplore();
}

export function commitExplore() {
	return currentGame.commitExplore();
}

export function discardExplore() {
	return currentGame.discardExplore();
}

export function canUndo() {
	return currentGame.canUndo();
}

export function canRedo() {
	return currentGame.canRedo();
}

export function pauseGame() {
	timer.stop();
	gamePaused.set(true);
}

export function resumeGame() {
	timer.start();
	gamePaused.set(false);
}

export default {
	startNew,
	startCustom,
	loadSavedGame,
	exportSavedGame,
	getGameDebugText,
	canLoadSavedGame,
	undo,
	redo,
	startExplore,
	commitExplore,
	discardExplore,
	canUndo,
	canRedo,
	pause: pauseGame,
	resume: resumeGame
};
